#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isMinHeap(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n; i++) {
            int left_child = 2 * i + 1;
            int right_child = 2 * i + 2;
            if (left_child < n && nums[i] > nums[left_child]) {
                return false;
            }
            if (right_child < n && nums[i] > nums[right_child]) {
                return false;
            }
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    bool ans = sol.isMinHeap(nums);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
